CREATE TABLE "config_versions" (
    "id" SERIAL NOT NULL,
    "version" INTEGER NOT NULL,
    "changed_key" VARCHAR(100) NOT NULL,
    "old_value" TEXT,
    "new_value" TEXT,
    "changed_by" VARCHAR(100) NOT NULL,
    "company_code" VARCHAR(50) NOT NULL DEFAULT 'UNIV',
    "created_at" TIMESTAMP,
    "updated_at" TIMESTAMP,
    PRIMARY KEY ("id")
);

CREATE TABLE "document_types" (
    "id" SERIAL NOT NULL,
    "name" VARCHAR(100) NOT NULL,
    "slug" VARCHAR(120) NOT NULL,
    "is_required" BOOLEAN NOT NULL DEFAULT 'FALSE',
    "description" TEXT,
    "created_at" TIMESTAMP,
    "updated_at" TIMESTAMP,
    PRIMARY KEY ("id")
);

-- Data for document_types
INSERT INTO "document_types" ("id", "name", "slug", "is_required", "description", "created_at", "updated_at") VALUES (1, 'KTP Document', 'ktp-document', 1, NULL, '2026-04-17 17:14:37', '2026-04-17 17:14:37');

CREATE TABLE "error_logs" (
    "id" SERIAL NOT NULL,
    "user_id" INTEGER,
    "level" VARCHAR(20) NOT NULL DEFAULT 'error',
    "message" TEXT NOT NULL,
    "stack_trace" TEXT,
    "endpoint" VARCHAR(500),
    "ip_address" VARCHAR(50),
    "resolved_status" VARCHAR(255) NOT NULL DEFAULT 'open',
    "resolved_by" VARCHAR(100),
    "resolved_at" TIMESTAMP,
    "company_code" VARCHAR(50) NOT NULL DEFAULT 'UNIV',
    "created_at" TIMESTAMP,
    "updated_at" TIMESTAMP,
    PRIMARY KEY ("id")
);

